import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET

interface ApiService {
    @GET("users")
    suspend fun fetchUserProfiles(): List<UserProfile>

    companion object {
        private const val DEV_URL = "https://dev-api.example.com/"
        private const val STAGING_URL = "https://staging-api.example.com/"
        private const val PROD_URL = "https://api.example.com/"

        fun create(environment: Environment, authToken: String): ApiService {
            val url = when (environment) {
                Environment.DEV -> DEV_URL
                Environment.STAGING -> STAGING_URL
                Environment.PROD -> PROD_URL
            }

            val logger = HttpLoggingInterceptor().apply { level = HttpLoggingInterceptor.Level.BASIC }

            val client = OkHttpClient.Builder()
                .addInterceptor(logger)
                .addInterceptor { chain ->
                    val request = chain.request().newBuilder()
                        .addHeader("Authorization", "Bearer $authToken")
                        .build()
                    chain.proceed(request)
                }
                .build()

            return Retrofit.Builder()
                .baseUrl(url)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build()
                .create(ApiService::class.java)
        }
    }
}

data class UserProfile(val id: String, val name: String, val email: String)

enum class Environment {
    DEV, STAGING, PROD
}